import{_ as t,o as r,c as n,ae as o}from"./chunks/framework.EHGTsUvI.js";const h=JSON.parse('{"title":"Overview","description":"","frontmatter":{},"headers":[],"relativePath":"guide/about.md","filePath":"guide/about.md"}'),i={name:"guide/about.md"};function a(s,e,l,d,c,p){return r(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><p>Semantic-TypeScript marks a significant leap forward in stream processing technology, <strong>synthesising</strong> the most effective concepts from JavaScript <code>GeneratorFunction</code>, Java Streams, and MySQL-style indexing. Its core philosophy is both simple and powerful: construct exceptionally efficient data-processing pipelines through intelligent indexing, not through brute-force iteration.</p><p>Where conventional libraries impose synchronous loops or unwieldy promise chains, Semantic-TypeScript delivers a <strong>fully asynchronous</strong>, functionally pure, and rigorously type-safe experience, designed for the demands of modern front-end development.</p><p>In its elegant model, data only reaches the consumer when the upstream pipeline explicitly invokes the <code>accept</code> (and optionally <code>interrupt</code>) callbacks. You have complete control over the timing—exactly when it is needed.</p><h2 id="why-developers-prefer-it" tabindex="-1">Why Developers Prefer It <a class="header-anchor" href="#why-developers-prefer-it" aria-label="Permalink to &quot;Why Developers Prefer It&quot;">​</a></h2><ul><li><strong>Zero-Boilerplate Indexing</strong> — every element carries its natural or bespoke index.</li><li><strong>Pure Functional Style</strong> — with full TypeScript inference.</li><li><strong>Leak-Proof Event Streams</strong> — <code>useWindow</code>, <code>useDocument</code>, <code>useHTMLElement</code>, and <code>useWebSocket</code> are built with safety in mind. You define the boundary—using <code>limit(n)</code>, <code>sub(start, end)</code>, or <code>takeWhile(predicate)</code>—and the library manages the cleanup. No lingering listeners, no memory leaks.</li><li><strong>Built-in Statistics</strong> — comprehensive numeric and bigint analytics including averages, medians, modes, variance, skewness, and kurtosis.</li><li><strong>Predictable Performance</strong> — choose between ordered or unordered collectors based on your requirements.</li><li><strong>Memory-Efficient</strong> — streams are evaluated lazily, alleviating memory concerns.</li><li><strong>No Undefined Behaviour</strong> — TypeScript guarantees type safety and nullability. Input data remains unmodified unless explicitly altered within your callback functions.</li></ul><h2 id="ready-to-explore" tabindex="-1">Ready to Explore? <a class="header-anchor" href="#ready-to-explore" aria-label="Permalink to &quot;Ready to Explore?&quot;">​</a></h2><p>Semantic-TypeScript transforms complex data flows into readable, composable, and high-performance pipelines. Whether you are handling real-time UI events, processing large datasets, or building analytics dashboards, it provides the power of database-grade indexing with the elegance of functional programming.</p><p><strong>Semantic-TypeScript</strong> — where streams meet structure.</p><p>Begin building today and experience the difference that thoughtful indexing delivers.</p><p><strong>Build with clarity, proceed with confidence, and transform data with intent.</strong></p>',11)])])}const g=t(i,[["render",a]]);export{h as __pageData,g as default};
